SELECT series_description 
FROM indicators 
WHERE data_quality_score = (SELECT MAX(data_quality_score) FROM indicators);

SELECT series_description
FROM indicators
WHERE indicator_code = '15.1.1';

SELECT indicator_code, series_code, data_quality_score 
FROM indicators 
WHERE indicator_id = 1;

SELECT *
FROM geographical_areas
WHERE geo_area_name = 'British Virgin Islands';
